code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, Button, Avatar, icon } from 'decantr/components';

code.example:
function ModerationQueueItem({ item, onApprove, onReject }) {
  const { div, h3, p, span, a, time } = tags;

  return Card({ class: css('_flex _col') },
    div({ class: css('_flex _aic _jcsb _p4 _borderb _bordermuted/20') },
      div({ class: css('_flex _aic _gap2') },
        Badge({ variant: 'outline', size: 'sm' }, item.type),
        h3({ class: css('_textsm _fontmedium') }, item.name),
        Badge({ variant: 'warning', size: 'xs' }, 'Pending')
      ),
      time({ class: css('_textxs _fgmuted') }, item.submitted_at)
    ),
    div({ class: css('_flex _aic _gap3 _px4 _py3 _bgmuted/5') },
      Avatar({ src: item.submitter.avatar, size: 'sm' }),
      div({ class: css('_flex _col _gap1') },
        span({ class: css('_textsm _fontmedium') }, item.submitter.name),
        div({ class: css('_flex _aic _gap2') },
          Badge({ variant: item.submitter.trusted ? 'success' : 'secondary', size: 'xs' },
            item.submitter.trusted ? 'Trusted' : `Rep: ${item.submitter.reputation}`
          )
        )
      )
    ),
    div({ class: css('_p4 _flex _col _gap2') },
      p({ class: css('_bodysm _fgmuted') }, item.description),
      a({ href: `/admin/moderation/${item.id}`, class: css('_textsm _fgprimary _hover:underline') }, 'View full content')
    ),
    div({ class: css('_flex _aic _jcfe _gap2 _p4 _bordert _bordermuted/20') },
      Button({ variant: 'outline', size: 'sm', onclick: () => onReject(item.id) },
        icon('x', { size: '0.875rem' }), ' Reject'
      ),
      Button({ variant: 'primary', size: 'sm', onclick: () => onApprove(item.id) },
        icon('check', { size: '0.875rem' }), ' Approve'
      )
    )
  );
}

